import{_ as i,c as e,o as s,ah as l}from"./chunks/framework.Cnj7lwEt.js";const k=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/Wasmer-开发工具.md","filePath":"github汇总/开发工具/Wasmer-开发工具.md"}'),r={name:"github汇总/开发工具/Wasmer-开发工具.md"};function h(t,a,o,n,d,c){return s(),e("div",null,a[0]||(a[0]=[l('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Wasmer</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>wasmerio</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><ol><li>WebAssembly运行环境缺乏统一、安全、高效的解决方案</li><li>需要在多种平台（桌面、云端、边缘设备、浏览器）运行相同代码</li><li>传统容器体积过大，启动慢</li><li>WebAssembly与现有编程语言集成复杂</li><li>安全访问控制难以管理</li></ol><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ol><li>极速安全的WebAssembly运行时</li><li>支持超轻量级容器在任何地方运行</li><li>默认安全的沙箱环境</li><li>支持WASIX、WASI等标准</li><li>接近原生的运行速度</li><li>支持多种编程语言SDK集成</li><li>多平台支持（Linux、macOS、Windows）</li><li>多种安装方式</li></ol><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ol><li>默认安全，无文件、网络、环境访问权限（除非明确启用）</li><li>可插拔架构，支持WASIX、WASI</li><li>极速性能，接近原生速度</li><li>支持多种编程语言SDK（Rust、C、C++、C#、Python、JavaScript、Go、PHP、Ruby、Java等）</li><li>安装简单，一条命令即可完成</li></ol><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/wasmerio/wasmer" target="_blank" rel="noreferrer">https://github.com/wasmerio/wasmer</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="_1-教程适用对象与环境范围" tabindex="-1">1. 教程适用对象与环境范围 <a class="header-anchor" href="#_1-教程适用对象与环境范围" aria-label="Permalink to “1. 教程适用对象与环境范围”">​</a></h2><p>适用于需要使用WebAssembly的开发者，支持Linux、macOS、Windows等主流操作系统</p><h2 id="_2-前置条件检查" tabindex="-1">2. 前置条件检查 <a class="header-anchor" href="#_2-前置条件检查" aria-label="Permalink to “2. 前置条件检查”">​</a></h2><ul><li>Linux/macOS：需要curl</li><li>Windows：需要PowerShell</li><li>其他安装方式请参考对应包管理器要求</li></ul><h2 id="_3-主路径-安装与启动" tabindex="-1">3. 主路径：安装与启动 <a class="header-anchor" href="#_3-主路径-安装与启动" aria-label="Permalink to “3. 主路径：安装与启动”">​</a></h2><h3 id="步骤1-linux-macos安装" tabindex="-1">步骤1：Linux/macOS安装 <a class="header-anchor" href="#步骤1-linux-macos安装" aria-label="Permalink to “步骤1：Linux/macOS安装”">​</a></h3><p>步骤目标：在Linux或macOS上安装Wasmer 执行位置：终端（本机） 完整命令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://get.wasmer.io</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSfL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><p>成功标志：终端显示安装成功信息，可运行<code>wasmer --version</code>查看版本 失败处理：检查网络连接，或尝试其他安装方式</p><h3 id="步骤2-windows安装-powershell" tabindex="-1">步骤2：Windows安装（PowerShell） <a class="header-anchor" href="#步骤2-windows安装-powershell" aria-label="Permalink to “步骤2：Windows安装（PowerShell）”">​</a></h3><p>步骤目标：在Windows上安装Wasmer 执行位置：PowerShell（本机） 完整命令：</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iwr https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">win.wasmer.io </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">useb </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p>成功标志：PowerShell显示安装成功信息，可运行<code>wasmer --version</code>查看版本 失败处理：检查网络连接，确保PowerShell执行策略允许，或尝试其他安装方式</p><h3 id="步骤3-快速体验wasmer" tabindex="-1">步骤3：快速体验Wasmer <a class="header-anchor" href="#步骤3-快速体验wasmer" aria-label="Permalink to “步骤3：快速体验Wasmer”">​</a></h3><p>步骤目标：运行一个示例程序验证安装 执行位置：终端/PowerShell（本机） 完整命令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wasmer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cowsay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello world&quot;</span></span></code></pre></div><p>成功标志：终端显示ASCII艺术的奶牛图案和&quot;hello world&quot;文字 失败处理：检查Wasmer是否正确安装，或查看官方文档排查问题</p><h2 id="_4-安装成功验证" tabindex="-1">4. 安装成功验证 <a class="header-anchor" href="#_4-安装成功验证" aria-label="Permalink to “4. 安装成功验证”">​</a></h2><ul><li>运行<code>wasmer --version</code>，显示版本号</li><li>运行<code>wasmer run cowsay &quot;test&quot;</code>，能正常显示输出</li></ul><h2 id="_5-常见错误排查" tabindex="-1">5. 常见错误排查 <a class="header-anchor" href="#_5-常见错误排查" aria-label="Permalink to “5. 常见错误排查”">​</a></h2><ol><li><p>现象 -&gt; curl命令失败 可能原因 -&gt; 网络连接问题或防火墙限制 解决步骤 -&gt; 检查网络连接，配置代理，或尝试其他安装方式</p></li><li><p>现象 -&gt; wasmer命令找不到 可能原因 -&gt; 环境变量未正确配置 解决步骤 -&gt; 重新打开终端，或手动将Wasmer安装路径添加到PATH环境变量</p></li><li><p>现象 -&gt; 运行示例程序失败 可能原因 -&gt; Wasmer安装不完整 解决步骤 -&gt; 重新安装Wasmer，或查看官方文档：<a href="https://docs.wasmer.io" target="_blank" rel="noreferrer">https://docs.wasmer.io</a> <a href="/网络环境.html">海外网络环境配置 →</a></p></li></ol><h2 id="_6-备选部署路径" tabindex="-1">6. 备选部署路径 <a class="header-anchor" href="#_6-备选部署路径" aria-label="Permalink to “6. 备选部署路径”">​</a></h2><ul><li>Homebrew（macOS, Linux）：<code>brew install wasmer</code></li><li>Scoop（Windows）：<code>scoop install wasmer</code></li><li>Chocolatey（Windows）：<code>choco install wasmer</code></li><li>Cargo：<code>cargo binstall wasmer-cli</code> 或 <code>cargo install wasmer-cli</code></li></ul><h2 id="_7-信息缺失说明" tabindex="-1">7. 信息缺失说明 <a class="header-anchor" href="#_7-信息缺失说明" aria-label="Permalink to “7. 信息缺失说明”">​</a></h2><p>更多详细使用教程请访问Wasmer官方文档：<a href="https://docs.wasmer.io" target="_blank" rel="noreferrer">https://docs.wasmer.io</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',42)]))}const m=i(r,[["render",h]]);export{k as __pageData,m as default};
